/**
 * Decodes hex-encoded HTTP response bodies from tshark output
 * and looks for practice/n2 data.
 */
import { decodePayload } from '../src/nitto-cipher.js';

// The hex strings from tshark output - paste the http.file_data field values here
const hexResponses = [
  // The large gameCode response at 10.073s (lnSYdP family - likely login/init)
  // The gameCode response at 11.592s (lgRYPP family)
  // content.htm at 11.908s
  "2273222c20312c202264222c20223c6e32202f3e22",
  // The hjVebd responses at 25-26s - these look like practice responses
  "",
];

for (const hex of hexResponses) {
  // Convert hex to string
  const str = hex.replace(/\s/g, '');
  let decoded = '';
  for (let i = 0; i < str.length; i += 2) {
    decoded += String.fromCharCode(parseInt(str.slice(i, i+2), 16));
  }
  
  console.log('\n=== Raw decoded ===');
  console.log(decoded.slice(0, 200));
  
  // Try Nitto cipher decode
  try {
    const result = decodePayload(decoded);
    console.log('=== Nitto decoded ===');
    console.log(result.decoded.slice(0, 500));
    if (result.decoded.includes('n2') || result.decoded.includes('practice')) {
      console.log('*** FOUND PRACTICE/N2 DATA ***');
      console.log(result.decoded);
    }
  } catch (e) {
    // Not cipher encoded - might be plain text
    if (decoded.includes('"s"') || decoded.includes('n2')) {
      console.log('=== Plain response ===');
      console.log(decoded);
    }
  }
}
